section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/edge-and-cdn-strategy.json",
  "type": "object",
  "required": [
    "platform",
    "routes",
    "fallback_dns_record",
    "per_request_cost_budget_usd",
    "cache_hit_ratio_target",
    "auth_handoff_method"
  ],
  "properties": {
    "platform": {
      "type": "string",
      "description": "enum (cloudflare | lambda_edge | fastly_compute | akamai)"
    },
    "routes": {
      "type": "array",
      "description": "array (each {pattern, cache_ttl, cache_key, auth_at_edge, origin_shield})"
    },
    "fallback_dns_record": {
      "type": "string",
      "description": "string"
    },
    "per_request_cost_budget_usd": {
      "type": "number",
      "description": "number"
    },
    "cache_hit_ratio_target": {
      "type": "number",
      "description": "number"
    },
    "auth_handoff_method": {
      "type": "string",
      "description": "enum (jwt_signed | mtls | shared_secret)"
    }
  }
}
